import{_ as r,o,c as s,a3 as t}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"25. Overtime","description":"","frontmatter":{"title":"25. Overtime","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","overtime","shift-work","employment"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/hours-of-work/25-overtime.md","filePath":"ebas/has-managers-admin/health-allied-services/hours-of-work/25-overtime.md"}'),a={name:"ebas/has-managers-admin/health-allied-services/hours-of-work/25-overtime.md"};function i(n,e,l,h,d,p){return o(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="_25-overtime" tabindex="-1">25. Overtime <a class="header-anchor" href="#_25-overtime" aria-label="Permalink to &quot;25. Overtime&quot;">​</a></h1><p>For the purposes of this clause, in accruing or calculating payment of overtime, each period of overtime will stand alone.</p><p><strong>25.1</strong> Where an Employee is required to work reasonable additional hours, they will be entitled to payment of overtime in accordance with the provisions of this clause.</p><p><strong>25.2</strong> Overtime, other than for time worked during the daylight savings change over period prescribed at subclause 49.1 of Section 1, means work that is performed:</p><p><strong>(a)</strong> by a full-time employee, where:</p><p><strong>(i)</strong> work is performed in excess of the rostered shift length on a particular day; or,</p><p><strong>(ii)</strong> work is performed in excess of ordinary hours as prescribed in subclause 22.1 of Section 2; or,</p><p><strong>(iii)</strong> work is performed in excess of twelve hours in any one shift,</p><p><strong>(b)</strong> by a part-time employee, where:</p><p><strong>(i)</strong> work is performed in excess of ordinary hours as prescribed in subclause 22.1 of Section 2; or</p><p><strong>(ii)</strong> the Employer directs the Employee to work additional hours beyond those agreed in <a href="/eba/ebas/has-managers-admin/health-allied-services/allowances/21-security-officer-certificate-allowance.html">clause 21.3</a> of Section 1, but excluding where an Employee is offered and accepts additional ordinary hours as described at subclause 21.10 (Additional Hours) of</p><p><strong>(iii)</strong> work is performed in excess of twelve hours in any one shift,</p><p><strong>(c)</strong> by a casual employee where:</p><p><strong>(i)</strong> work is performed in excess of ordinary hours as prescribed in subclause 24.1 of Section 2; or</p><p><strong>(ii)</strong> work is performed in excess of twelve hours in any one shift.</p><p><strong>25.3</strong> Only authorised overtime will be paid for at the following overtime rates:</p><p><strong>(a)</strong> For Overtime that arises pursuant to subclause 25.2(a)-25.2(b).</p><p><strong>(i)</strong> 150% (based on 1/38th of the weekly salary set out in Schedule 2B) for the first two hours and 200% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a>) thereafter.</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',19)])])}const f=r(a,[["render",i]]);export{m as __pageData,f as default};
